// TG-144: Fetch tomorrow's scheduled jobs from Supabase
const supabaseUrl = 'https://lwtmvzhwekgdxkaisfra.supabase.co/rest/v1';
const supabaseKey = 'sb_publishable_DeX21ldoDKl3NyJeFZzR1w_eWBUkx-v';
const supabaseHeaders = {
  'apikey': supabaseKey,
  'Authorization': `Bearer ${supabaseKey}`
};

// Calculate tomorrow's date in CT (UTC-5/6)
const now = new Date();
const ctOffset = -6; // CST; adjust to -5 for CDT
const ctNow = new Date(now.getTime() + ctOffset * 60 * 60 * 1000);
const tomorrow = new Date(ctNow);
tomorrow.setDate(tomorrow.getDate() + 1);
const tomorrowStr = tomorrow.toISOString().split('T')[0];

let jobs = [];
try {
  jobs = await this.helpers.httpRequest({
    method: 'GET',
    url: `${supabaseUrl}/jobber_email_events?event_type=eq.job_scheduled&parsed_scheduled_date=eq.${tomorrowStr}&select=client_name,client_address,job_description,parsed_scheduled_time`,
    headers: supabaseHeaders
  });
} catch (e) {
  jobs = [];
}

if (!Array.isArray(jobs) || jobs.length === 0) {
  return [{ json: { jobs: [], _skip: true, message: 'No jobs scheduled for tomorrow' } }];
}

return [{ json: { jobs, tomorrowStr } }];

// TG-144: Build crew field reminder messages with marketing checklist
const data = $input.first().json;
if (data._skip) {
  return [{ json: { message: `No jobs scheduled for tomorrow. Enjoy the evening!`, jobCount: 0 } }];
}

const jobs = data.jobs;
const tomorrowStr = data.tomorrowStr;

const jobMessages = jobs.map((job, i) => {
  const name = job.client_name || 'Unknown';
  const address = job.client_address || 'Address TBD';
  const service = job.job_description || 'Service TBD';
  const time = job.parsed_scheduled_time || 'Time TBD';

  return [
    `JOB ${i + 1}`,
    `Customer: ${name}`,
    `Address: ${address}`,
    `Service: ${service}`,
    `Time: ${time}`,
    '',
    'FIELD MARKETING CHECKLIST:',
    '[ ] Place yard sign in visible location',
    '[ ] Leave 3 door hangers at neighboring houses',
    '[ ] Carry business cards',
    '[ ] Take before/after photos',
    '[ ] Ask customer for Google review'
  ].join('\n');
});

const fullMessage = [
  `TOMORROW'S JOB REMINDERS`,
  `Date: ${tomorrowStr}`,
  `Total Jobs: ${jobs.length}`,
  '',
  '---',
  '',
  jobMessages.join('\n\n---\n\n')
].join('\n');

return [{ json: { message: fullMessage, jobCount: jobs.length } }];

// TG-144: Log reminder run to automation_runs
const supabaseUrl = 'https://lwtmvzhwekgdxkaisfra.supabase.co/rest/v1';
const supabaseKey = 'sb_publishable_DeX21ldoDKl3NyJeFZzR1w_eWBUkx-v';

const jobCount = $input.first().json.jobCount || 0;

try {
  await this.helpers.httpRequest({
    method: 'POST',
    url: `${supabaseUrl}/automation_runs`,
    headers: {
      'apikey': supabaseKey,
      'Authorization': `Bearer ${supabaseKey}`,
      'Content-Type': 'application/json',
      'Prefer': 'return=minimal'
    },
    body: {
      workflow_name: 'TG-144',
      event_type: 'crew_field_reminder',
      status: 'success',
      details: { job_count: jobCount },
      created_at: new Date().toISOString()
    }
  });
} catch (e) { /* continue on fail */ }

return [{ json: { logged: true, jobCount } }];
